options.getOption:
// 沪港通·深港通 境内投资者地理分布 — ECharts China Map
var echartsLib = (typeof context !== 'undefined' && context && context.echarts) ? context.echarts : (typeof echarts !== 'undefined' ? echarts : null);
var chartInstance = (typeof context !== 'undefined' && context && context.panel && context.panel.chart) ? context.panel.chart : (typeof echartsInstance !== 'undefined' ? echartsInstance : null);

var cityData = [
  {name: '香港', value: [114.17, 22.32, 62.40, 56]},
  {name: '上海', value: [121.47, 31.23, 48.23, 125]},
  {name: '北京', value: [116.41, 39.90, 35.67, 98]},
  {name: '深圳', value: [114.06, 22.54, 28.91, 82]},
  {name: '广州', value: [113.27, 23.13, 18.76, 43]},
  {name: '杭州', value: [120.15, 30.27, 12.34, 38]},
  {name: '天津', value: [117.20, 39.08, 9.23, 32]},
  {name: '成都', value: [104.07, 30.57, 8.76, 29]},
  {name: '武汉', value: [114.31, 30.59, 7.56, 25]},
  {name: '南京', value: [118.80, 32.06, 6.54, 21]},
  {name: '重庆', value: [106.55, 29.56, 5.43, 18]},
  {name: '西安', value: [108.94, 34.34, 4.89, 15]},
  {name: '济南', value: [117.12, 36.65, 4.12, 14]},
  {name: '沈阳', value: [123.43, 41.80, 3.67, 12]},
  {name: '合肥', value: [117.23, 31.82, 3.21, 11]}
];

var buildOption = function() {
  return {
    backgroundColor: '#040D1C',
    geo: {
      map: 'china',
      roam: false,
      center: [108, 36],
      zoom: 1.22,
      itemStyle: {
        areaColor: '#0A1A35',
        borderColor: '#1E4D99',
        borderWidth: 0.9
      },
      emphasis: { disabled: true },
      select: { disabled: true },
      silent: true,
      label: { show: false }
    },
    series: [{
      type: 'effectScatter',
      coordinateSystem: 'geo',
      data: cityData,
      symbolSize: function(val) { return Math.max(8, Math.sqrt(val[2]) * 4.2); },
      rippleEffect: { brushType: 'stroke', scale: 3.2, period: 3 },
      itemStyle: { color: '#00E5FF', shadowBlur: 18, shadowColor: 'rgba(0,229,255,0.55)' },
      label: { show: true, formatter: '{b}', position: 'right', color: '#90CAF9', fontSize: 11 },
      z: 10
    }],
    tooltip: {
      trigger: 'item',
      backgroundColor: 'rgba(4,13,28,0.92)',
      borderColor: '#1565C0',
      borderWidth: 1,
      padding: [8, 12],
      textStyle: { color: '#E0E0E0', fontSize: 12 },
      formatter: function(params) {
        var v = params.value;
        return '<div style="font-weight:bold;color:#00E5FF;margin-bottom:5px;font-size:13px">' + params.name + '</div>' +
          '成交量：<span style="color:#00E5FF;font-weight:bold">' + v[2] + ' 亿港元</span><br/>' +
          '投资者数：<span style="color:#69FF47;font-weight:bold">' + v[3] + ' 万人</span>';
      }
    }
  };
};

if (!echartsLib.getMap('china')) {
  fetch('https://cdn.jsdelivr.net/gh/longwosion/geojson-map-china@master/china.json')
    .then(function(r) { return r.json(); })
    .then(function(geoJson) {
      echartsLib.registerMap('china', geoJson);
      chartInstance.setOption(buildOption());
    })
    .catch(function(err) { console.error('China GeoJSON load error:', err); });
  return { backgroundColor: '#040D1C' };
} else {
  return buildOption();
}

